const fcData=[{"w":"M.E.T.A.S (técnicamente)","a":"🏗️ Aplicación <strong>web estática y offline-first</strong> que se distribuye por tres frentes (web, PWA, APK) desde un mismo código, con <strong>Supabase</strong> como nube para lo único que necesita servidor."},{"w":"Web estática","a":"📄 El sitio son archivos <strong>HTML, CSS y JS tal cual</strong>: ningún programa \"arma\" las páginas en un servidor. GitHub Pages solo los entrega."},{"w":"Offline-first","a":"🔌 La app funciona <strong>primero sin internet</strong>: los datos viven en el dispositivo (localStorage) y la nube es copia/extensión, nunca un requisito."},{"w":"PWA","a":"📱 <em>Progressive Web App</em>: la misma página web, pero <strong>instalable</strong> con ícono propio y capaz de abrir sin conexión gracias al service worker."},{"w":"Service worker (sw.js)","a":"📦 Guarda una <strong>copia local del sitio</strong>. Su versión (hoy v27) se sube en cada cambio publicado para que los teléfonos tomen la copia nueva."},{"w":"Capacitor","a":"🤖 Herramienta que <strong>envuelve el mismo código web</strong> dentro de un APK Android (id com.policastsapien.metas). No se reescribió nada."},{"w":"APK firmado","a":"🔐 La app Android se firma con un <strong>keystore</strong> y sube su <strong>versionCode</strong> en cada entrega; es requisito para distribuir y para Play Store."},{"w":"Supabase","a":"☁️ <strong>Backend como servicio</strong>: PostgreSQL en la nube con funciones (RPC) y reglas de seguridad (RLS). Solo hace lo que exige servidor."},{"w":"localStorage","a":"💾 Almacén local del navegador donde <strong>nacen y viven</strong> los datos del usuario (claves METAS_*). Es la fuente de verdad; la nube es el espejo."},{"w":"Outbox","a":"📤 <strong>Cola local de salida</strong>: cada evento pendiente espera ahí y se envía cuando hay internet. Un corte de luz no pierde nada."},{"w":"evento_id","a":"🏷️ Identificador <strong>único por evento</strong>: si un envío se reintenta, la nube reconoce lo ya recibido y <strong>no duplica filas</strong>."},{"w":"GitHub Pages","a":"🌐 Hosting <strong>gratuito de archivos estáticos</strong>: cada git push publica el sitio. No hay servidor propio que mantener."},{"w":"CNAME","a":"🔗 Archivo de <strong>una sola línea</strong> en el repo que apunta el sitio al dominio propio: metas.policastsapien.com."},{"w":"RPC","a":"🚪 Funciones de la base de datos que son la <strong>única puerta de entrada</strong> del cliente: nadie toca las tablas directamente."},{"w":"RLS (Row Level Security)","a":"🛡️ Reglas de PostgreSQL que deciden <strong>qué filas</strong> puede ver o tocar cada quien. Por eso la clave pública no es un riesgo."},{"w":"Código de aula y clave de familia","a":"🧒 El alumno se identifica con un <strong>código</strong> (nunca su nombre) y cada familia consulta con su <strong>clave propia</strong>: minimización de datos de menores."}];
