const routeSets=[{"label":"El viaje de un dato","steps":["El alumno termina la evaluación","Se guarda al instante en localStorage","Una copia entra al outbox con su evento_id","Con internet, el lote sube a Supabase","El maestro y la familia lo consultan en la nube"]},{"label":"Publicar un cambio en la web","steps":["Editar el código en la PC","Commit en Git (respaldo por paso)","git push a GitHub","GitHub Pages actualiza el sitio","Subir la versión del service worker","Los teléfonos toman la copia nueva"]},{"label":"Del código al APK Android","steps":["npm run build:www copia el código a www/","npx cap sync lo lleva al proyecto Android","Gradle compila el APK","Se firma con el keystore","Se sube el versionCode y se distribuye"]}];
let currentRouteIdx=0,routeItems=[];
function buildRoute(){routeItems=_shuffle([...routeSets[currentRouteIdx].steps]);renderRoute();const fbEl=document.getElementById('fbRoute');if(fbEl)fbEl.classList.remove('show');}
function renderRoute(){const list=document.getElementById('routeList');if(!list)return;list.innerHTML='';routeItems.forEach((step,i)=>{const div=document.createElement('div');div.className='sort-item';div.innerHTML=`<div class="sort-arrows"><button class="sort-arrow" onclick="routeMove(${i},-1)"${i===0?' disabled':''}>▲</button><button class="sort-arrow" onclick="routeMove(${i},1)"${i===routeItems.length-1?' disabled':''}>▼</button></div><div class="sort-step-num">${i+1}.</div><div class="sort-item-txt">${step}</div>`;list.appendChild(div);});}
function routeMove(idx,dir){sfx('click');const ni=idx+dir;if(ni<0||ni>=routeItems.length)return;[routeItems[idx],routeItems[ni]]=[routeItems[ni],routeItems[idx]];renderRoute();}
