const completeTaskDB=[{"s":"El sitio se publica en GitHub ___ con dominio propio.","opts":["Actions","Pages","Gist"],"ans":"Pages"},{"s":"Los datos del usuario viven primero en ___.","opts":["la nube","localStorage","un servidor"],"ans":"localStorage"},{"s":"El ___ reintenta subir los eventos cuando vuelve el internet.","opts":["outbox","cron","socket"],"ans":"outbox"},{"s":"La deduplicación en la nube usa el campo ___.","opts":["evento_id","fecha","nombre"],"ans":"evento_id"},{"s":"El APK se firma con un ___ para poder distribuirse.","opts":["keystore","token","hash"],"ans":"keystore"},{"s":"La nube del proyecto corre en el plan ___ de Supabase.","opts":["Enterprise","Free","Pro"],"ans":"Free"},{"s":"npm run ___ lleva el código web al proyecto Android.","opts":["sync","test","deploy"],"ans":"sync"},{"s":"El asistente de las familias es la página ___.","opts":["padres.html","index.html","registro.html"],"ans":"padres.html"}];
const explainQuestions=[{"q":"¿Por qué M.E.T.A.S no tiene servidor propio y por qué eso es una fortaleza?","ans":"El frontend es estático (GitHub Pages) y lo único que exige servidor lo hace Supabase como servicio. Menos piezas propias significa menos que se cae, menos que mantener y costo ~$0, condición para que sea sostenible en una escuela pública."},{"q":"Explica el viaje de un dato desde que el alumno termina la evaluación hasta que la familia lo consulta.","ans":"Nace en el dispositivo, se guarda al instante en localStorage, una copia entra al outbox con su evento_id, sube a Supabase cuando hay internet (los reintentos no duplican por el id único) y el maestro o la familia lo consultan mediante funciones RPC."},{"q":"¿Qué es una PWA y qué papel juega el service worker y su versión?","ans":"Es la misma página web pero instalable y capaz de abrir sin conexión. El service worker guarda la copia local; subir su versión (v26→v27) en cada cambio hace que los teléfonos suelten la copia vieja."},{"q":"¿Cómo se logra que web, PWA y APK salgan de un mismo código?","ans":"El código es HTML/CSS/JS puro sin compilación. La web y la PWA se publican con git push; Capacitor envuelve exactamente el mismo código (webDir www) en un APK Android firmado. Tres frentes, un solo desarrollo."},{"q":"¿Por qué la clave anon de Supabase puede ir en el código sin ser una fuga?","ans":"Porque está diseñada para el cliente: solo permite lo que las reglas RLS y las funciones RPC autorizan (las escrituras exigen además cuenta docente). La clave peligrosa es la service_role, que nunca sale del servidor."}];
let ansVisible=false;
function genTask(){sfx('click');const type=document.getElementById('tgType').value;const count=parseInt(document.getElementById('tgCount').value);ansVisible=false;const out=document.getElementById('tgOut');out.innerHTML='';if(type==='identify')genIdentifyTask(out,count);else if(type==='classify')genClassifyTask(out,count);else if(type==='complete')genCompleteTask(out,count);else if(type==='explain')genExplainTask(out,count);fin('s-tareas');}
function _instrBlock(out,title,lines){const ib=document.createElement('div');ib.className='tg-instruction-block';ib.innerHTML=`<h4>📋 ${title}</h4>`+lines.map(l=>`<p>${l}</p>`).join('');out.appendChild(ib);}
function genIdentifyTask(out,count){_instrBlock(out,'Instrucción',['Copia en tu cuaderno; subraya, colorea o encierra el concepto técnico ilustrado en cada oración. Escribe al lado de qué concepto se trata.','<strong>Ejemplo:</strong> Un solo contraejemplo basta para refutar una ley. → <span style="color:var(--jade);font-weight:700;">Falsacionismo</span>']);_pick(identifyTaskDB,Math.min(count,identifyTaskDB.length)).forEach((item,i)=>{const div=document.createElement('div');div.className='tg-task';div.innerHTML=`<div class="tg-task-num">${i+1}</div><div class="tg-task-content"><strong>${item.s}</strong><div style="border-bottom:1.5px solid var(--border);min-width:220px;margin-top:0.5rem;height:1.3rem;">&nbsp;</div><div class="tg-answer">✅ ${item.type}</div></div>`;out.appendChild(div);});}
function genClassifyTask(out,count){_instrBlock(out,'Instrucción',['Copia la siguiente tabla en tu cuaderno. Para cada elemento, completa su tipo, características, ámbito y función.']);const items=_pick(classifyTaskDB,Math.min(count,classifyTaskDB.length));const wrap=document.createElement('div');wrap.style.overflowX='auto';const th=(t,extra='')=>`<th style="padding:0.3rem 0.4rem;border:1px solid var(--border);font-size:0.72rem;text-align:center;${extra}">${t}</th>`;let html=`<table style="width:100%;border-collapse:collapse;font-size:0.78rem;min-width:520px;"><thead><tr style="background:var(--pri-gl);">${th('Elemento','text-align:left;')}${th('Tipo')}${th('Características')}${th('Ámbito')}${th('Función')}</tr></thead><tbody>`;items.forEach(it=>{html+=`<tr><td style="padding:0.4rem 0.5rem;border:1px solid var(--border);font-weight:600;">${it.w}</td>`+Array(4).fill(`<td style="padding:0.4rem;border:1px solid var(--border);min-width:50px;"></td>`).join('')+'</tr>';});html+='</tbody></table>';wrap.innerHTML=html;out.appendChild(wrap);const ans=document.createElement('div');ans.className='tg-answer';ans.style.marginTop='0.8rem';ans.innerHTML='<strong>✅ Respuestas:</strong><br>'+items.map(it=>`<strong>${it.w}:</strong> Tipo: ${it.gen} | Características: ${it.n} | Ámbito: ${it.g} | Función: ${it.t}`).join('<br>');out.appendChild(ans);}
function genCompleteTask(out,count){_instrBlock(out,'Instrucción',['Copia y resuelve en tu cuaderno. Cada oración tiene un espacio ___. Elige y escribe la opción correcta.']);const pool=_shuffle([...completeTaskDB]);for(let i=0;i<count;i++){const item=pool[i%pool.length];const div=document.createElement('div');div.className='tg-task';const sent=item.s.replace('___','<span class="tg-blank" style="min-width:90px;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>');div.innerHTML=`<div class="tg-task-num">${i+1}</div><div class="tg-task-content"><strong>${sent}</strong><div style="margin-top:0.4rem;font-size:0.82rem;color:var(--gray);">📝 Opciones: <strong>${item.opts.join(' | ')}</strong></div><div class="tg-answer">✅ ${item.ans}</div></div>`;out.appendChild(div);}}
function genExplainTask(out,count){_instrBlock(out,'Instrucción',['Copia las siguientes preguntas en tu cuaderno y responde cada una de forma clara y argumentada.']);const pool=_shuffle([...explainQuestions]);for(let i=0;i<count;i++){const item=pool[i%pool.length];const div=document.createElement('div');div.className='tg-task';div.innerHTML=`<div class="tg-task-num">${i+1}</div><div class="tg-task-content"><strong>${item.q}</strong><div style="border-bottom:1.5px solid var(--border);min-width:200px;margin-top:0.5rem;height:1.3rem;">&nbsp;</div><div style="border-bottom:1.5px solid var(--border);min-width:200px;margin-top:0.3rem;height:1.3rem;">&nbsp;</div><div class="tg-answer">✅ ${item.ans}</div></div>`;out.appendChild(div);}}
function toggleAns(){ansVisible=!ansVisible;document.querySelectorAll('.tg-answer').forEach(el=>el.style.display=ansVisible?'block':'none');sfx('click');}

