// ===================== LÍNEA DE TIEMPO INTERACTIVA =====================
const timelineData=[{"y":"Inicio","icon":"🌱","label":"Primeras misiones de español","text":"El proyecto nace como colección de actividades HTML de gramática (adjetivos, verbos) para enseñar de forma lúdica y visual. Ahí se siembra el molde de 3 archivos por misión."},{"y":"2026","icon":"🎮","label":"El molde madura: 32 misiones","text":"Las misiones crecen con estructura idéntica (HTML+JS+CSS, 13 secciones didácticas): reparar una enseña a reparar todas y replicar es cuestión de horas."},{"y":"11 jul","icon":"☁️","label":"Nace la nube (Supabase)","text":"Resultados y progreso offline-first suben a PostgreSQL vía funciones RPC; panel docente y Plan de Acción en la nube con claves de familia por alumno."},{"y":"12 jul","icon":"🌐","label":"Dominio propio","text":"La app migra a <strong>metas.policastsapien.com</strong>: archivo CNAME en el repo + GitHub Pages. Un dominio corto y profesional para compartir."},{"y":"14 jul","icon":"🛡️","label":"Blindaje de seguridad","text":"Auditoría profunda: las escrituras exigen cuenta docente, rate-limit por IP real (Cloudflare), RLS exacta, y el <strong>código de aula</strong> saca los nombres de los menores de la plataforma."},{"y":"15 jul","icon":"👥","label":"Roles y primera tracción","text":"Ajustes con roles docente/director/rector/admin desplegados; una maestra internacional queda encantada con la demo: primeras señales de mercado."},{"y":"16-17 jul","icon":"🤝","label":"Asistente de padres redondo","text":"Fecha de la prueba restaurada y deduplicación doble (nube + teléfono): cada evaluación aparece UNA sola vez para la familia."},{"y":"~8 ago","icon":"🚀","label":"Meta: Play Store","text":"El siguiente hito: 100 misiones y la publicación del APK firmado en Play Store."}];
function initTimeline(){const track=document.getElementById('timelineTrack');if(!track)return;timelineData.forEach((d,i)=>{const b=document.createElement('button');b.className='tl-node';b.type='button';b.dataset.idx=i;b.innerHTML=`<span class="tl-dot">${d.icon}</span><span class="tl-year">${d.y}</span><span class="tl-label">${d.label}</span>`;b.onclick=()=>showTimeline(i);track.appendChild(b);});}
function showTimeline(i){const d=timelineData[i];document.querySelectorAll('.tl-node').forEach(n=>n.classList.remove('tl-active'));document.querySelector(`.tl-node[data-idx="${i}"]`).classList.add('tl-active');document.getElementById('tlInfoIcon').textContent=d.icon;document.getElementById('tlInfoText').innerHTML=`<strong>${d.y} — ${d.label}.</strong> ${d.text}`;document.getElementById('tlInfo').classList.add('show');sfx('click');}

// ===================== SIMULACIÓN: MÉTODO DE POPPER =====================
let methodRunning=false;
function startMethod(){if(methodRunning)return;methodRunning=true;sfx('click');document.getElementById('methodBtn').style.display='none';document.getElementById('methodBranch').classList.remove('show');document.getElementById('methodResult').innerHTML='';const steps=['ms1','ms2','ms3','ms4'];const arrows=['ma1','ma2','ma3'];steps.forEach(s=>document.getElementById(s).classList.remove('active','done'));arrows.forEach(a=>document.getElementById(a).classList.remove('active'));let i=0;function next(){if(i>0){document.getElementById(steps[i-1]).classList.remove('active');document.getElementById(steps[i-1]).classList.add('done');}if(i<steps.length){if(i>0)document.getElementById(arrows[i-1]).classList.add('active');document.getElementById(steps[i]).classList.add('active');sfx('ok');i++;setTimeout(next,900);}else{document.getElementById('methodBranch').classList.add('show');}}next();}
function resolveMethod(conInternet){sfx(conInternet?'ok':'no');document.getElementById('methodBranch').classList.remove('show');document.getElementById('ms4').classList.remove('active');document.getElementById('ms4').classList.add('done');const r=document.getElementById('methodResult');if(conInternet){r.innerHTML='<div class="method-step done" style="opacity:1;"><span class="ms-num">5</span><span class="ms-icon">☁️</span><span class="ms-text"><strong>Enviado:</strong> la fila llega a Supabase. Si algo se reintenta, el evento_id único evita duplicados.</span></div><div class="method-arrow active" style="margin:0.4rem 0;">⬇️</div><div class="method-step done" style="opacity:1;"><span class="ms-num">6</span><span class="ms-icon">👨‍🏫</span><span class="ms-text"><strong>Consulta:</strong> el maestro lo ve en su panel y la familia en el asistente, cada quien con su clave.</span></div>';}else{r.innerHTML='<div class="method-step done" style="opacity:1;border-color:var(--red);background:var(--red-gl);"><span class="ms-num">5</span><span class="ms-icon">📤</span><span class="ms-text"><strong>Sin señal:</strong> el evento espera en la cola local (outbox). Nada se pierde — ni con un corte de luz.</span></div><div class="method-arrow active" style="margin:0.4rem 0;">⬇️</div><div class="method-step done" style="opacity:1;"><span class="ms-num">6</span><span class="ms-icon">🔄</span><span class="ms-text"><strong>Reintento automático:</strong> al volver el internet, el lote sube solo y el evento_id evita duplicar.</span></div>';}methodRunning=false;document.getElementById('methodBtn').style.display='inline-flex';document.getElementById('methodBtn').textContent='🔄 Repetir simulación';sfx('fan');}

