const parteData={"web":{"nombre":"Web (GitHub Pages)","icon":"🌐","estructura":{"title":"Qué es","info":"• El frente más directo: el sitio en <strong>metas.policastsapien.com</strong><br>• Archivos <strong>estáticos</strong> (HTML/CSS/JS) entregados por GitHub Pages<br>• El dominio propio se configura con el archivo <strong>CNAME</strong> (una línea)<br>• No requiere instalar nada: cualquier navegador sirve"},"funcion":{"title":"Cómo funciona","info":"• Cada <strong>git push</strong> a la rama main publica el sitio automáticamente<br>• No hay compilación: lo que está en el repo es lo que corre<br>• GitHub Pages solo ENTREGA archivos; toda la lógica corre en el navegador del usuario<br>• El hosting es gratuito: parte del diseño de costo ~$0"},"enfermedades":{"title":"Riesgos y límites","info":"• En plan Free de GitHub, Pages exige que el repositorio sea <strong>público</strong><br>• Si GitHub cae (raro), el sitio no carga para visitantes nuevos — pero la PWA instalada sigue abriendo<br>• Sitio público = cualquiera ve el código: por eso NINGUNA clave secreta vive en él"},"cuidados":{"title":"Ejemplo real","info":"• El 12 de julio de 2026 la app migró del subdominio largo de github.io al dominio propio<br>• Se actualizaron ~74 archivos y el CNAME en un solo despliegue<br>• Desde entonces, compartir la app es decir: <strong>metas.policastsapien.com</strong>"}},"pwa":{"nombre":"PWA instalable","icon":"📱","estructura":{"title":"Qué es","info":"• La MISMA página web, pero <strong>instalable</strong> con ícono propio<br>• Abre <strong>sin conexión</strong> gracias a la copia local del service worker<br>• Hay 2 manifiestos: el de la app general y el del asistente de padres<br>• Es el frente preferido de las familias: se instala desde el navegador, sin tienda"},"funcion":{"title":"Cómo funciona","info":"• <strong>sw.js</strong> declara CACHE_NAME (hoy v27) y la lista de archivos a guardar<br>• Al publicar un cambio se <strong>sube la versión</strong>: los teléfonos sueltan la copia vieja<br>• El manifest.json define nombre, ícono y color de la app instalada<br>• Si no hay señal, el asistente de padres muestra su último caché avisando la fecha"},"enfermedades":{"title":"Riesgos y límites","info":"• Olvidar subir la versión del sw = familias viendo la app <strong>vieja</strong> indefinidamente<br>• El caché ocupa espacio en el teléfono (controlado: solo assets esenciales)<br>• iOS es más restrictivo con PWA que Android (limitación de plataforma, no del proyecto)"},"cuidados":{"title":"Ejemplo real","info":"• El arreglo del duplicado del asistente (17 jul) subió sw de v26 a <strong>v27</strong><br>• Sin ese número nuevo, los teléfonos de los padres habrían seguido mostrando 4 pruebas en vez de 3<br>• El QR que se reparte a las familias instala directamente la PWA del asistente"}},"apk":{"nombre":"APK Android","icon":"🤖","estructura":{"title":"Qué es","info":"• La app <strong>nativa</strong> de Android — sin haber reescrito una sola misión<br>• <strong>Capacitor</strong> envuelve el código web (webDir: www) en un paquete instalable<br>• Identidad: <strong>com.policastsapien.metas</strong> (capacitor.config.json)<br>• Las únicas 4 dependencias del proyecto son de Capacitor"},"funcion":{"title":"Cómo funciona","info":"• <strong>npm run sync</strong>: copia el código a www/ y lo lleva al proyecto Android<br>• <strong>Gradle</strong> compila; el APK se firma con el <strong>keystore</strong> del autor<br>• Cada entrega sube el <strong>versionCode</strong><br>• Plugins nativos usados: Filesystem y Share (guardar/compartir constancias)"},"enfermedades":{"title":"Riesgos y límites","info":"• Perder el keystore = no poder actualizar la app publicada (se respalda con cuidado)<br>• Play Protect desconfía de APKs con targetSdk viejo: hay que mantenerlo al día<br>• El contenido web del APK NO se actualiza con git push: requiere recompilar o abrir la versión web"},"cuidados":{"title":"Ejemplo real","info":"• En las pruebas con APK instalado, Play Protect marcó una versión con targetSdk viejo; la fuente ya apunta a SDK 36<br>• Meta ~8 de agosto de 2026: publicar el APK firmado en <strong>Play Store</strong>"}},"nube":{"nombre":"Nube (Supabase)","icon":"☁️","estructura":{"title":"Qué es","info":"• <strong>Backend como servicio</strong>: PostgreSQL en la nube, plan Free<br>• Hace SOLO lo que exige servidor: sincronizar dispositivos, panel docente, asistente de padres<br>• ~18 archivos SUPABASE-*.sql en el repo documentan cada tabla y función<br>• Cloudflare va al frente: aporta la IP real para el rate-limit"},"funcion":{"title":"Cómo funciona","info":"• El cliente NUNCA toca tablas: solo llama <strong>funciones RPC</strong> (metas_guardar, metas_consultar_plan_padre…)<br>• Las escrituras exigen <strong>cuenta docente</strong> (PROF-XXXX + contraseña)<br>• <strong>RLS</strong> decide qué filas ve cada quien; DELETE/UPDATE sin WHERE están bloqueados<br>• La consulta del padre deduplica: cada evaluación aparece una sola vez"},"enfermedades":{"title":"Riesgos y límites","info":"• Plan Free ≈ 500 MB: antes de nov 2026 se necesita el ciclo anual de archivado<br>• Dependencia de un tercero gratuito: mitigada porque la nube es COPIA, no fuente de verdad<br>• Fase 2 de seguridad pendiente: bcrypt para contraseñas y token de sesión"},"cuidados":{"title":"Ejemplo real","info":"• Caso 26-9GW3 (17 jul): una fila vieja sin parcial duplicaba una prueba en el asistente<br>• Se corrigió EN LA FUNCIÓN RPC: la fila sin parcial cede ante su corrección — sin borrar datos<br>• Verificado con curl: la clave devuelve exactamente 3 pruebas"}}};
let labParte='web',labAspecto='estructura';
function labShowParte(parteKey){labParte=parteKey;updateLabDisplay();document.querySelectorAll('.lab-cont-btn').forEach(b=>b.classList.remove('active-pri'));const btn=document.querySelector(`[data-parte="${parteKey}"]`);if(btn)btn.classList.add('active-pri');if(typeof sfx==='function')sfx('click');}
function labShowAspecto(aspectoKey){labAspecto=aspectoKey;updateLabDisplay();document.querySelectorAll('.lab-asp-btn').forEach(b=>b.classList.remove('active-sec'));const btn=document.querySelector(`[data-aspecto="${aspectoKey}"]`);if(btn)btn.classList.add('active-sec');if(typeof sfx==='function')sfx('click');}
function updateLabDisplay(){const data=parteData[labParte];const asp=data[labAspecto];document.getElementById('lab-sentence').innerHTML=`🦉 Explorando: <strong>${data.nombre}</strong> → <strong>${asp.title}</strong>`;document.getElementById('lab-display').innerHTML=`<div class="lab-cont-header">${data.icon} ${data.nombre}</div><div class="lab-asp-title">${asp.title}</div><div class="lab-asp-info">${asp.info}</div>`;}

// ===================== DIPLOMA =====================
function _diplPct(){return xp>=MXP?100:Math.round((xp/MXP)*100);}
function openDiploma(){sfx('fan');const pct=_diplPct();document.getElementById('diplPct').textContent=pct+'%';document.getElementById('diplBar').style.width=pct+'%';document.getElementById('diplDate').textContent='Fecha: '+new Date().toLocaleDateString('es-HN',{year:'numeric',month:'long',day:'numeric'});const msgs=['¡Sigue estudiando tu sistema!','¡Muy buen trabajo!','¡Excelente arquitecto en formación!','¡Dominas el panorama de M.E.T.A.S!','¡Maestro del Panorama Técnico!'];document.getElementById('diplMsg').textContent=msgs[Math.min(Math.floor(pct/25),4)];const stars=['⭐','⭐⭐','⭐⭐⭐'];document.getElementById('diplStars').textContent=stars[Math.min(Math.floor(pct/40),2)];const achTxt=unlockedAch.map(id=>ACHIEVEMENTS[id].icon+' '+ACHIEVEMENTS[id].label).join(' · ');document.getElementById('diplAch').textContent=achTxt||'Sigue completando secciones para desbloquear logros';document.getElementById('diplomaOverlay').classList.add('open');launchConfetti();}
function closeDiploma(){document.getElementById('diplomaOverlay').classList.remove('open');}
function updateDiplomaName(v){document.getElementById('diplName').textContent=v||'Estudiante';}
function shareWA(){const name=document.getElementById('diplName').textContent||'Estudiante';const pct=_diplPct();const msg='🏗️ ¡'+name+' completó el Módulo 1 de Autocapacitación M.E.T.A.S (Panorama técnico)! 🏅 Progreso: '+pct+'% · ⚙️ policastsapien.com';window.open('https://wa.me/?text='+encodeURIComponent(msg),'_blank');}
async function captureDiploma(){if(typeof html2canvas==='undefined'){showToast('⚠️ Cargando... intenta de nuevo');return;}sfx('click');const card=document.querySelector('.diploma-card');const btn=document.querySelector('.diploma-actions .btn-pri');const toHide=[card.querySelector('.diploma-input'),card.querySelector('.diploma-actions'),card.querySelector('hr')];if(btn){btn.disabled=true;btn.textContent='⏳ Capturando...';}toHide.forEach(el=>{if(el)el.style.display='none';});let dataUrl='';try{const canvas=await html2canvas(card,{scale:2,useCORS:true,backgroundColor:'#ffffff'});toHide.forEach(el=>{if(el)el.style.display='';});dataUrl=canvas.toDataURL('image/png');const name=(document.getElementById('diplName').textContent||'Estudiante').replace(/\s+/g,'-');const fileName='constancia-'+name+'.png';const cap=window.Capacitor;if(cap&&cap.isNativePlatform&&cap.isNativePlatform()&&cap.Plugins?.Filesystem&&cap.Plugins?.Share){const base64Data=dataUrl.split(',')[1];const result=await cap.Plugins.Filesystem.writeFile({path:fileName,data:base64Data,directory:'CACHE'});await cap.Plugins.Share.share({url:result.uri,dialogTitle:'Guardar / Compartir Constancia'});}else{const a=document.createElement('a');a.href=dataUrl;a.download=fileName;a.click();}}catch(e){toHide.forEach(el=>{if(el)el.style.display='';});if(e.name!=='AbortError')showToast('⚠️ No se pudo guardar la constancia');}finally{if(btn){btn.disabled=false;btn.textContent='📷 Guardar foto';}}}

